{"output":"import { CustomFieldType, ICustomField } from '@domain/customField';
import { ApiClient } from '@service/anedot/client';
import { PaginatedResponse, PaginationParams } from '@service/anedot/interfaces';
import { useGetAccount } from '@state/accounts';
import { generateQueryKey, resourceKeys } from '@state/cacheHelper';
import { makeSearchParams } from '@utils';
import { useQuery } from 'react-query';

type Props = {
  ids?: string[];
  inputType?: CustomFieldType;
  internalName?: string;
  paginationParams?: PaginationParams;
  q?: string;
};

const DEFAULT_PAGE = 1;
// There isn't a UI for pagination, and we expect form fields to not exceed maybe 5+ ish.
const DEFAULT_PAGE_SIZE = 1000;

export const useGetAllCustomFields = ({ paginationParams, ...restParams }: Props = {}) => {
  const { currentAccount } = useGetAccount();
  const accountId = currentAccount?.id;
  const { page, perPage } = paginationParams ?? { page: DEFAULT_PAGE, perPage: DEFAULT_PAGE_SIZE };
  const params = makeSearchParams({
    account_id: accountId,
    page,
    per_page: perPage,
    ...restParams,
  });

  const query = useQuery<PaginatedResponse<ICustomField[]>, string>(
    generateQueryKey({
      accountId,
      parameters: { page, perPage },
      resourceKey: resourceKeys.customFields,
    }),
    async () => {
      return new ApiClient().get<PaginatedResponse<ICustomField[]>>(
        `/action_pages_custom_fields?${params.toString()}`
      );
    },
    {
      enabled: !!accountId,
    }
  );

  return {
    customFields: query.data?.data,
    isLoading: query.isLoading,
    meta: query.data?.meta,
  };
};
